class Solution:
    def minimumString(self, a: str, b: str, c: str) -> str:
        def merge(s1: str, s2: str) -> str:
            if s2 in s1:
                return s1
            if s1 in s2:
                return s2
            for i in range(min(len(s1), len(s2)) + 1:
                if s1.endswith(s2[:i]):
                    return s1 + s2[i:]
                if s2.endswith(s1[:i]):
                    return s2 + s1[i:]
            return s1 + s2

        from itertools import permutations

        res = []
        for order in permutations([a, b, c]):
            merged = merge(merge(order[0], order[1]), order[2])
            res.append(merged)
        return min(res)
